///  single-source shortest path execution.
class FPC {
  FPC._(this._bc, this._bcOffset);
  factory FPC(List<int> bytes) {
    final rootRef = fb.BufferContext.fromBytes(bytes);
    return reader.read(rootRef, 0);
  }

  static const fb.Reader<FPC> reader = _FPCReader();

  final fb.BufferContext _bc;
  final int _bcOffset;

  FPCGraphDefinition? get GRAPH_DEFINITION => FPCGraphDefinition.reader.vTableGetNullable(_bc, _bcOffset, 4);
  FPCGraphDefinition? get graphDefinition => GRAPH_DEFINITION;
  FPCWeightedEdgeList? get EDGES => FPCWeightedEdgeList.reader.vTableGetNullable(_bc, _bcOffset, 6);
  FPCCSRGraph? get CSR => FPCCSRGraph.reader.vTableGetNullable(_bc, _bcOffset, 8);
  FPCShortestPathRequest? get SHORTEST_PATH_REQUEST => FPCShortestPathRequest.reader.vTableGetNullable(_bc, _bcOffset, 10);
  FPCShortestPathRequest? get shortestPathRequest => SHORTEST_PATH_REQUEST;
  FPCShortestPathResult? get SHORTEST_PATH_RESULT => FPCShortestPathResult.reader.vTableGetNullable(_bc, _bcOffset, 12);
  FPCShortestPathResult? get shortestPathResult => SHORTEST_PATH_RESULT;
  FPCPathRequest? get PATH_REQUEST => FPCPathRequest.reader.vTableGetNullable(_bc, _bcOffset, 14);
  FPCPathRequest? get pathRequest => PATH_REQUEST;
  FPCPathResult? get PATH_RESULT => FPCPathResult.reader.vTableGetNullable(_bc, _bcOffset, 16);
  FPCPathResult? get pathResult => PATH_RESULT;

  @override
  String toString() {
    return 'FPC{graphDefinition: ${graphDefinition}, EDGES: ${EDGES}, CSR: ${CSR}, shortestPathRequest: ${shortestPathRequest}, shortestPathResult: ${shortestPathResult}, pathRequest: ${pathRequest}, pathResult: ${pathResult}}';
  }
}

class _FPCReader extends fb.TableReader<FPC> {
  const _FPCReader();

  @override
  FPC createObject(fb.BufferContext bc, int offset) => 
    FPC._(bc, offset);
}

class FPCBuilder {
  FPCBuilder(this.fbBuilder);

  final fb.Builder fbBuilder;

  void begin() {
    fbBuilder.startTable(7);
  }

  int addGraphDefinitionOffset(int? offset) {
    fbBuilder.addOffset(0, offset);
    return fbBuilder.offset;
  }
  int addEdgesOffset(int? offset) {
    fbBuilder.addOffset(1, offset);
    return fbBuilder.offset;
  }
  int addCsrOffset(int? offset) {
    fbBuilder.addOffset(2, offset);
    return fbBuilder.offset;
  }
  int addShortestPathRequestOffset(int? offset) {
    fbBuilder.addOffset(3, offset);
    return fbBuilder.offset;
  }
  int addShortestPathResultOffset(int? offset) {
    fbBuilder.addOffset(4, offset);
    return fbBuilder.offset;
  }
  int addPathRequestOffset(int? offset) {
    fbBuilder.addOffset(5, offset);
    return fbBuilder.offset;
  }
  int addPathResultOffset(int? offset) {
    fbBuilder.addOffset(6, offset);
    return fbBuilder.offset;
  }

  int finish() {
    return fbBuilder.endTable();
  }
}

class FPCObjectBuilder extends fb.ObjectBuilder {
  final FPCGraphDefinitionObjectBuilder? _GRAPH_DEFINITION;
  final FPCWeightedEdgeListObjectBuilder? _EDGES;
  final FPCCSRGraphObjectBuilder? _CSR;
  final FPCShortestPathRequestObjectBuilder? _SHORTEST_PATH_REQUEST;
  final FPCShortestPathResultObjectBuilder? _SHORTEST_PATH_RESULT;
  final FPCPathRequestObjectBuilder? _PATH_REQUEST;
  final FPCPathResultObjectBuilder? _PATH_RESULT;

  FPCObjectBuilder({
    FPCGraphDefinitionObjectBuilder? GRAPH_DEFINITION,
    FPCGraphDefinitionObjectBuilder? graphDefinition,
    FPCWeightedEdgeListObjectBuilder? EDGES,
    FPCCSRGraphObjectBuilder? CSR,
    FPCShortestPathRequestObjectBuilder? SHORTEST_PATH_REQUEST,
    FPCShortestPathRequestObjectBuilder? shortestPathRequest,
    FPCShortestPathResultObjectBuilder? SHORTEST_PATH_RESULT,
    FPCShortestPathResultObjectBuilder? shortestPathResult,
    FPCPathRequestObjectBuilder? PATH_REQUEST,
    FPCPathRequestObjectBuilder? pathRequest,
    FPCPathResultObjectBuilder? PATH_RESULT,
    FPCPathResultObjectBuilder? pathResult,
  })
      : _GRAPH_DEFINITION = graphDefinition ?? GRAPH_DEFINITION,
        _EDGES = EDGES,
        _CSR = CSR,
        _SHORTEST_PATH_REQUEST = shortestPathRequest ?? SHORTEST_PATH_REQUEST,
        _SHORTEST_PATH_RESULT = shortestPathResult ?? SHORTEST_PATH_RESULT,
        _PATH_REQUEST = pathRequest ?? PATH_REQUEST,
        _PATH_RESULT = pathResult ?? PATH_RESULT;

  /// Finish building, and store into the [fbBuilder].
  @override
  int finish(fb.Builder fbBuilder) {
    final int? GRAPH_DEFINITIONOffset = _GRAPH_DEFINITION?.getOrCreateOffset(fbBuilder);
    final int? EDGESOffset = _EDGES?.getOrCreateOffset(fbBuilder);
    final int? CSROffset = _CSR?.getOrCreateOffset(fbBuilder);
    final int? SHORTEST_PATH_REQUESTOffset = _SHORTEST_PATH_REQUEST?.getOrCreateOffset(fbBuilder);
    final int? SHORTEST_PATH_RESULTOffset = _SHORTEST_PATH_RESULT?.getOrCreateOffset(fbBuilder);
    final int? PATH_REQUESTOffset = _PATH_REQUEST?.getOrCreateOffset(fbBuilder);
    final int? PATH_RESULTOffset = _PATH_RESULT?.getOrCreateOffset(fbBuilder);
    fbBuilder.startTable(7);
    fbBuilder.addOffset(0, GRAPH_DEFINITIONOffset);
    fbBuilder.addOffset(1, EDGESOffset);
    fbBuilder.addOffset(2, CSROffset);
    fbBuilder.addOffset(3, SHORTEST_PATH_REQUESTOffset);
    fbBuilder.addOffset(4, SHORTEST_PATH_RESULTOffset);
    fbBuilder.addOffset(5, PATH_REQUESTOffset);
    fbBuilder.addOffset(6, PATH_RESULTOffset);
    return fbBuilder.endTable();
  }

  /// Convenience method to serialize to byte list.
  @override
  Uint8List toBytes([String? fileIdentifier]) {
    final fbBuilder = fb.Builder(deduplicateTables: false);
    fbBuilder.finish(finish(fbBuilder), fileIdentifier);
    return fbBuilder.buffer;
  }
}
